// Handler convention: module src/handlers/<name>.js exports { name, handle }
// where name is kebab-case and equals the filename stem, and
// handle(x) returns `${name}:${x}`.
module.exports = { name: "alpha", handle: (x) => `alpha:${x}` };

// Registers every handler and re-exports the registry surface.
const registry = require("./registry.js");
const alpha = require("./handlers/alpha.js");
registry.register(alpha);
module.exports = { register: registry.register, all: registry.all };

const test = require("node:test");
const assert = require("node:assert");
const { all } = require("../src/index.js");

const NAME_RE = /^[a-z]+(-[a-z]+)*$/;

test("every registered handler honors the convention", () => {
  const handlers = all();
  assert.ok(handlers.length >= 1, "at least one handler must be registered");
  for (const h of handlers) {
    assert.ok(NAME_RE.test(h.name), `name not kebab-case: ${h.name}`);
    assert.strictEqual(
      h.handle("z"),
      h.name + ":z",
      `handle output mismatch for ${h.name}`
    );
  }
});
